```lean
-- Target: DefeasiblyHolds (R2, qualified_residence_interest)
-- Defeaters: E2.1 (TCJA suspension), D1/D2 (IRS discretion)
-- Key challenge: open_texture "qualified_residence" requires parametric predicates
def QualifiedResidence (prop : Property) : Prop := 
  -- Core: primary residence ∨ (secondary ∧ personal_use ≥ 14_days)
  -- Penumbra: timeshares, boats, vacant land (IRS discretion)
  ∃ (taxpayer : Taxpayer), PrimaryResidence taxpayer prop ∨ 
                          (SecondaryResidence taxpayer prop ∧ PersonalUseDays ≥ 14)

-- TCJA defeat relation (2018 ≤ tax_year ≤ 2025)
def TCJAHomeEquityDefeat (debt : HomeEquityDebt) : Defeater R2 := 
  TaxYear ∈ [2018, 2025] ∧ ¬(ProceedsUsedForImprovement debt)
```

